index 7673c3548175..8efc2f116d5c 100644
--- a/llvm/lib/Analysis/ScalarEvolution.cpp
+++ b/llvm/lib/Analysis/ScalarEvolution.cpp
@@ -15338,6 +15338,10 @@ void ScalarEvolution::LoopGuards::collectFromPHI(
     const PHINode &Phi, SmallPtrSetImpl<const BasicBlock *> &VisitedBlocks,
     SmallDenseMap<const BasicBlock *, LoopGuards> &IncomingGuards,
     unsigned Depth) {
+  // Prevent infinite recursion by limiting the depth of recursive calls.
+  // This can happen with cyclic PHI dependencies.
+  if (Depth > 32)
+    return;
   if (!SE.isSCEVable(Phi.getType()))
     return;

